// ─── LOGIN PAGE ───────────────────────────────────────────────────────────────
function LoginPage({ onLogin }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => {
      if (email === "chairman@mallareddy.edu.in" && password === "chairman@2025") {
        onLogin();
      } else {
        setError("Invalid credentials. Use demo credentials below.");
      }
      setLoading(false);
    }, 900);
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-header">
          <div className="login-logo">MR</div>
          <div className="login-title">Chairman Portal</div>
          <div className="login-subtitle">Malla Reddy College of Engineering</div>
        </div>
        <div className="login-body">
          <div className="login-welcome">
            <h5>Welcome, Mr. Malla Reddy</h5>
            <p>Sign in to access your Chairman Dashboard</p>
          </div>
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label className="form-label">Email Address</label>
              <input
                type="email" className="form-control"
                placeholder="chairman@mallareddy.edu.in"
                value={email} onChange={e => setEmail(e.target.value)} required
              />
            </div>
            <div className="mb-3">
              <label className="form-label">Password</label>
              <input
                type="password" className="form-control"
                placeholder="Enter your password"
                value={password} onChange={e => setPassword(e.target.value)} required
              />
            </div>
            {error && <div className="alert alert-danger py-2 px-3 mb-3" style={{ fontSize: "0.82rem", borderRadius: "8px" }}>{error}</div>}
            <button type="submit" className="btn-login" disabled={loading}>
              {loading ? "Authenticating…" : "Sign In to Portal"}
            </button>
          </form>
          <div className="login-hint">
            Demo: chairman@mallareddy.edu.in / chairman@2025
          </div>
        </div>
      </div>
    </div>
  );
}

