    { name: "Fee Collection Report", desc: "Detailed fee collection, pending dues, and department-wise breakdown", icon: "💰", color: "#e67e22", count: "AY 2025–26" },
    { name: "Transport Report", desc: "Bus routes, driver details, student assignments, and maintenance records", icon: "🚌", color: "#1abc9c", count: "6 routes" },
    { name: "Annual Academic Report", desc: "Annual academic performance, results, and institutional statistics", icon: "📊", color: "#e74c3c", count: "AY 2024–25" },
  ];

  return (
    <div>
      <div className="section-card mb-4">
        <div className="section-title">Reports Center</div>
        <div className="section-subtitle">Download official institutional reports — last updated: November 10, 2025</div>
        <div className="row g-3">
          {reports.map((r, i) => (
            <div key={i} className="col-md-4">
              <div className="report-card">
                <div className="report-icon" style={{ background: r.color + "18" }}>
                  <span style={{ fontSize: "2rem" }}>{r.icon}</span>
                </div>
                <div className="report-name">{r.name}</div>
                <div className="report-desc">{r.desc}</div>
                <div style={{ fontSize: "0.73rem", color: "var(--text-muted)", marginBottom: 12 }}>📁 {r.count}</div>
                <button className="btn-download" onClick={() => alert(`Downloading ${r.name}…`)}>
                  ⬇️ Download Report
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
      <div className="section-card">
        <div className="section-title">Generate Custom Report</div>
        <div className="section-subtitle">Configure and generate a tailored report</div>
        <div className="row g-3">
          <div className="col-md-4">
            <label className="form-label">Report Type</label>
            <select className="form-control">
              <option>Student Report</option><option>Faculty Report</option>
              <option>Fee Report</option><option>Attendance Report</option>
            </select>
          </div>
          <div className="col-md-3">
            <label className="form-label">Department</label>
            <select className="form-control"><option>All Departments</option>{DEPARTMENTS.map(d => <option key={d.id}>{d.name.split(" ")[0]}</option>)}</select>
          </div>
          <div className="col-md-3">
            <label className="form-label">Format</label>
            <select className="form-control"><option>PDF</option><option>Excel</option><option>CSV</option></select>
          </div>
          <div className="col-md-2 d-flex align-items-end">
            <button className="btn-download w-100" onClick={() => alert("Generating custom report…")}>⚙️ Generate</button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── MAIN APP ────────────────────────────────────────────────────────────────
export default function App() {
  const [loggedIn, setLoggedIn] = useState(false);
  const [page, setPage] = useState("dashboard");

  const pages = {
    dashboard: <DashboardPage />,
    departments: <DepartmentsPage />,
    faculty: <FacultyPage />,
    staff: <StaffPage />,
    transport: <TransportPage />,
    fee: <FeePage />,
    announcements: <AnnouncementsPage />,
    reports: <ReportsPage />,
  };

  return (
    <>
      <style>{CSS}</style>
      {!loggedIn ? (
        <LoginPage onLogin={() => setLoggedIn(true)} />
      ) : (
        <div className="app-layout">
          <Sidebar active={page} onNav={setPage} onLogout={() => setLoggedIn(false)} />
          <div className="main-wrap">
            <Topbar page={page} onLogout={() => setLoggedIn(false)} />
            <div className="content-area">{pages[page]}</div>
          </div>
        </div>
      )}
    </>
  );
}
